 4→@Injectable()
 5→export class EnvConfigService {
 6→	private readonly logger = new Logger(EnvConfigService.name);
 7→
 8→	constructor(private readonly configService: ConfigService) {}
 9→
10→	get<T = unknown>({
11→		key,
12→		converter,
13→	}: {
14→		key: string;
15→		converter?: (param: unknown) => T;
16→	}): T {
17→		this.logger.log(`Fetching env var: ${key}`);
18→
19→		const envVariable = this.configService.get<T>(key);
20→
21→		if (envVariable === undefined) {
22→			throw new Error(`Environment variable ${key} is not defined`);
23→		}
24→
25→		return converter ? converter(envVariable) : envVariable;
26→	}
27→}
