212→	async bulkInsert(
213→		pairs: {
214→			styleIdA: number;
215→			styleIdB: number;
216→			copurchaseCount: number;
217→		}[],
218→	): Promise<void> {
219→		try {
220→			const dataToInsert = pairs.map((pair) => {
221→				const minId = Math.min(pair.styleIdA, pair.styleIdB);
222→				const maxId = Math.max(pair.styleIdA, pair.styleIdB);
223→
224→				return {
225→					_id: randomUUID(),
226→					style_id_a: minId,
227→					style_id_b: maxId,
228→					copurchase_count: pair.copurchaseCount,
229→					created_at: this.knexWrite.fn.now(),
230→					updated_at: this.knexWrite.fn.now(),
231→					deleted_at: null,
232→				};
233→			});
234→
235→			const batchSize = 1000;
236→			for (let i = 0; i < dataToInsert.length; i += batchSize) {
237→				const batch = dataToInsert.slice(i, i + batchSize);
238→
239→				await this.knexWrite(this.tableName).insert(batch);
240→
241→				this.logger.debug(
242→					`Processed batch ${Math.floor(i / batchSize) + 1}/${Math.ceil(dataToInsert.length / batchSize)} (${batch.length} records)`,
243→				);
244→			}
245→
246→			this.logger.log(`Successfully inserted ${pairs.length} style copurchases`);
247→		} catch (error: unknown) {
248→			const err = error instanceof Error ? error : new Error(String(error));
249→			this.logger.error(`Failed to bulk insert style copurchases: ${err.message}`);
250→			throw err;
251→		}
252→	}
