1018→  async canActivate(context: ExecutionContext): Promise<boolean> {
1019→    // Check @Public() decorator
1020→    const isPublic = this.reflector.getAllAndOverride<boolean>(IS_PUBLIC_KEY, [
1021→      context.getHandler(),
1022→      context.getClass(),
1023→    ]);
1024→    if (isPublic) return true;
1025→
1026→    const request = context.switchToHttp().getRequest<FastifyRequest>();
1027→    const token = this.extractTokenFromHeader({ request });
1028→    if (!token) throw new UnauthorizedException();
1029→
1030→    const payload = await this.jwtService.verifyAsync<IJwtPayload>(token);
1031→    const session = await this.sessionService.getSession({
1032→      userId: payload.user_id,
1033→      sessionId: payload.session_id,
1034→    });
1035→    if (!session) throw new UnauthorizedException();
1036→
1037→    (request as any).user = {
1038→      user_id: payload.user_id,
1039→      session_id: payload.session_id,
1040→      role: session.role,
1041→      company_id: session.company_id,
1042→    } satisfies IRequestUser;
1043→
1044→    return true;
1045→  }
1046→
1047→  private extractTokenFromHeader({ request }: { request: FastifyRequest }): string | null {
