import * as fs from 'node:fs';
import * as path from 'node:path';

import { INestApplication } from '@nestjs/common';
import { Test, TestingModule } from '@nestjs/testing';
import * as dotenv from 'dotenv';

import {
	DATABASE_URL,
	DATABASE_URL_READ_REPLICA,
	ENCRYPTION_KEY,
	FRONTEND_URL,
	GITHUB_CALLBACK_URL,
	GITHUB_CLIENT_ID,
	GITHUB_CLIENT_SECRET,
	GLOBAL_PREFIX,
	GOOGLE_CALLBACK_URL,
	GOOGLE_CLIENT_ID,
	GOOGLE_CLIENT_SECRET,
	GRACEFUL_SHUTDOWN_DELAY,
	IS_COMPACT_LOGS,
	IS_JSON_LIKE_LOGS,
	JWT_ACCESS_TOKEN_EXPIRY,
	JWT_REFRESH_TOKEN_EXPIRY_DAYS,
	JWT_SECRET,
	NODE_ENV,
	PORT,
	REDIS_READ_URL,
	REDIS_URL,
	SERVER_NAME,
} from '../src/constants/env-variables.constant';
import { EnvConfigModule } from '../src/modules/env-config/env-config.module';
import { EnvConfigService } from '../src/modules/env-config/env-config.service';

describe('EnvConfigModule (e2e)', () => {
	let app: INestApplication;
	let envConfigService: EnvConfigService;
	const testEnvVariables: Record<string, string | number | boolean> = {};

	beforeAll(async () => {
		const envFilePath = path.resolve(process.cwd(), '.env.test');
		const envConfig = dotenv.parse(fs.readFileSync(envFilePath));

		testEnvVariables[NODE_ENV] = String(envConfig[NODE_ENV]);
		testEnvVariables[PORT] = Number(envConfig[PORT]);
		testEnvVariables[GLOBAL_PREFIX] = String(envConfig[GLOBAL_PREFIX]);
		testEnvVariables[SERVER_NAME] = String(envConfig[SERVER_NAME]);
		testEnvVariables[IS_COMPACT_LOGS] = envConfig[IS_COMPACT_LOGS] === 'true';
		testEnvVariables[IS_JSON_LIKE_LOGS] = envConfig[IS_JSON_LIKE_LOGS] === 'true';
		testEnvVariables[GRACEFUL_SHUTDOWN_DELAY] = Number(
			envConfig[GRACEFUL_SHUTDOWN_DELAY],
		);
		testEnvVariables[DATABASE_URL] = String(envConfig[DATABASE_URL]);
		testEnvVariables[DATABASE_URL_READ_REPLICA] = String(envConfig[DATABASE_URL_READ_REPLICA]);
		testEnvVariables[REDIS_URL] = String(envConfig[REDIS_URL]);
		testEnvVariables[REDIS_READ_URL] = String(envConfig[REDIS_READ_URL]);
		testEnvVariables[JWT_SECRET] = String(envConfig[JWT_SECRET]);
		testEnvVariables[JWT_ACCESS_TOKEN_EXPIRY] = Number(envConfig[JWT_ACCESS_TOKEN_EXPIRY]);
		testEnvVariables[JWT_REFRESH_TOKEN_EXPIRY_DAYS] = Number(envConfig[JWT_REFRESH_TOKEN_EXPIRY_DAYS]);
		testEnvVariables[GITHUB_CLIENT_ID] = String(envConfig[GITHUB_CLIENT_ID]);
		testEnvVariables[GITHUB_CLIENT_SECRET] = String(envConfig[GITHUB_CLIENT_SECRET]);
		testEnvVariables[GITHUB_CALLBACK_URL] = String(envConfig[GITHUB_CALLBACK_URL]);
		testEnvVariables[GOOGLE_CLIENT_ID] = String(envConfig[GOOGLE_CLIENT_ID]);
		testEnvVariables[GOOGLE_CLIENT_SECRET] = String(envConfig[GOOGLE_CLIENT_SECRET]);
		testEnvVariables[GOOGLE_CALLBACK_URL] = String(envConfig[GOOGLE_CALLBACK_URL]);
		testEnvVariables[FRONTEND_URL] = String(envConfig[FRONTEND_URL]);
		testEnvVariables[ENCRYPTION_KEY] = String(envConfig[ENCRYPTION_KEY]);

		const moduleFixture: TestingModule = await Test.createTestingModule({
			imports: [EnvConfigModule],
		}).compile();

		app = moduleFixture.createNestApplication();
		envConfigService = moduleFixture.get<EnvConfigService>(EnvConfigService);

		await app.init();
	});

	afterAll(async () => {
		await app.close();
	});

	describe('Module structure', () => {
		it('should initialise and export EnvConfigService', () => {
			expect(envConfigService).toBeDefined();
			expect(envConfigService).toBeInstanceOf(EnvConfigService);
		});
	});

	describe('Configuration loading', () => {
		it('should load string variables correctly', () => {
			expect(envConfigService.get<string>({ key: NODE_ENV })).toBe(
				testEnvVariables[NODE_ENV],
			);
			expect(envConfigService.get<string>({ key: GLOBAL_PREFIX })).toBe(
				testEnvVariables[GLOBAL_PREFIX],
			);
			expect(envConfigService.get<string>({ key: SERVER_NAME })).toBe(
				testEnvVariables[SERVER_NAME],
			);
		});

		it('should load numeric variables correctly with converter', () => {
			expect(envConfigService.get<number>({ key: PORT, converter: Number })).toBe(
				testEnvVariables[PORT],
			);
			expect(
				envConfigService.get<number>({ key: GRACEFUL_SHUTDOWN_DELAY, converter: Number }),
			).toBe(testEnvVariables[GRACEFUL_SHUTDOWN_DELAY]);
		});

		it('should load boolean variables and return a boolean type when converter is applied', () => {
			expect(
				typeof envConfigService.get<boolean>({
					key: IS_COMPACT_LOGS,
					converter: Boolean,
				}),
			).toBe('boolean');
			expect(
				typeof envConfigService.get<boolean>({
					key: IS_JSON_LIKE_LOGS,
					converter: Boolean,
				}),
			).toBe('boolean');
		});

		it('should load DATABASE_URL correctly', () => {
			expect(envConfigService.get<string>({ key: DATABASE_URL })).toBe(
				testEnvVariables[DATABASE_URL],
			);
		});

		it('should load DATABASE_URL_READ_REPLICA correctly', () => {
			expect(envConfigService.get<string>({ key: DATABASE_URL_READ_REPLICA })).toBe(
				testEnvVariables[DATABASE_URL_READ_REPLICA],
			);
		});

		it('should load REDIS_URL correctly', () => {
			expect(envConfigService.get<string>({ key: REDIS_URL })).toBe(
				testEnvVariables[REDIS_URL],
			);
		});

		it('should load REDIS_READ_URL correctly', () => {
			expect(envConfigService.get<string>({ key: REDIS_READ_URL })).toBe(
				testEnvVariables[REDIS_READ_URL],
			);
		});

		it('should load JWT_SECRET correctly', () => {
			expect(envConfigService.get<string>({ key: JWT_SECRET })).toBe(
				testEnvVariables[JWT_SECRET],
			);
		});

		it('should load JWT_ACCESS_TOKEN_EXPIRY correctly with converter', () => {
			expect(
				envConfigService.get<number>({ key: JWT_ACCESS_TOKEN_EXPIRY, converter: Number }),
			).toBe(testEnvVariables[JWT_ACCESS_TOKEN_EXPIRY]);
		});

		it('should load JWT_REFRESH_TOKEN_EXPIRY_DAYS correctly with converter', () => {
			expect(
				envConfigService.get<number>({ key: JWT_REFRESH_TOKEN_EXPIRY_DAYS, converter: Number }),
			).toBe(testEnvVariables[JWT_REFRESH_TOKEN_EXPIRY_DAYS]);
		});

		it('should load GITHUB_CLIENT_ID correctly', () => {
			expect(envConfigService.get<string>({ key: GITHUB_CLIENT_ID })).toBe(
				testEnvVariables[GITHUB_CLIENT_ID],
			);
		});

		it('should load GITHUB_CLIENT_SECRET correctly', () => {
			expect(envConfigService.get<string>({ key: GITHUB_CLIENT_SECRET })).toBe(
				testEnvVariables[GITHUB_CLIENT_SECRET],
			);
		});

		it('should load GITHUB_CALLBACK_URL correctly', () => {
			expect(envConfigService.get<string>({ key: GITHUB_CALLBACK_URL })).toBe(
				testEnvVariables[GITHUB_CALLBACK_URL],
			);
		});

		it('should load GOOGLE_CLIENT_ID correctly', () => {
			expect(envConfigService.get<string>({ key: GOOGLE_CLIENT_ID })).toBe(
				testEnvVariables[GOOGLE_CLIENT_ID],
			);
		});

		it('should load GOOGLE_CLIENT_SECRET correctly', () => {
			expect(envConfigService.get<string>({ key: GOOGLE_CLIENT_SECRET })).toBe(
				testEnvVariables[GOOGLE_CLIENT_SECRET],
			);
		});

		it('should load GOOGLE_CALLBACK_URL correctly', () => {
			expect(envConfigService.get<string>({ key: GOOGLE_CALLBACK_URL })).toBe(
				testEnvVariables[GOOGLE_CALLBACK_URL],
			);
		});

		it('should load FRONTEND_URL correctly', () => {
			expect(envConfigService.get<string>({ key: FRONTEND_URL })).toBe(
				testEnvVariables[FRONTEND_URL],
			);
		});

		it('should load ENCRYPTION_KEY correctly', () => {
			expect(envConfigService.get<string>({ key: ENCRYPTION_KEY })).toBe(
				testEnvVariables[ENCRYPTION_KEY],
			);
		});
	});

	describe('Error handling', () => {
		it('should throw for non-existent environment variable', () => {
			expect(() =>
				envConfigService.get<string>({ key: 'NON_EXISTENT_VARIABLE' }),
			).toThrow('Environment variable NON_EXISTENT_VARIABLE is not defined');
		});
	});

	describe('Type conversions', () => {
		it('should return numeric type when Number converter is used', () => {
			const port = envConfigService.get<number>({ key: PORT, converter: Number });
			expect(typeof port).toBe('number');
		});

		it('should provide config to downstream services via DI', async () => {
			const testModuleFixture: TestingModule = await Test.createTestingModule({
				imports: [EnvConfigModule],
				providers: [
					{
						provide: 'PORT_PROVIDER',
						useFactory: (config: EnvConfigService) =>
							config.get<number>({ key: PORT, converter: Number }),
						inject: [EnvConfigService],
					},
				],
			}).compile();

			const portValue = testModuleFixture.get<number>('PORT_PROVIDER');
			expect(portValue).toBe(testEnvVariables[PORT]);
		});
	});
});

