export const TABLE_NAME_USERS = 'users';
export const TABLE_NAME_OAUTH_ACCOUNTS = 'oauth_accounts';
export const TABLE_NAME_COMPANIES = 'companies';
export const TABLE_NAME_COMPANY_MEMBERS = 'company_members';
export const TABLE_NAME_INVITATIONS = 'invitations';

import { Global, Module } from '@nestjs/common';
import { KnexModule } from 'nest-knexjs';

import { getEnv } from '@utils/get-env-variable.util';

import { DATABASE_URL, DATABASE_URL_READ_REPLICA } from '@constants/env-variables.constant';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';

@Global()
@Module({
	imports: [
		KnexModule.forRoot(
			{
				name: KNEX_WRITE_CONNECTION,
				config: {
					client: 'pg',
					connection: {
						connectionString: getEnv<string>({ key: DATABASE_URL, converter: String }),
					},
					pool: {
						min: 2,
						max: 10,
						acquireTimeoutMillis: 10_000,
						idleTimeoutMillis: 30_000,
					},
				},
			},
			KNEX_WRITE_CONNECTION,
		),
		KnexModule.forRoot(
			{
				name: KNEX_READ_CONNECTION,
				config: {
					client: 'pg',
					connection: {
						connectionString: getEnv<string>({
							key: DATABASE_URL_READ_REPLICA,
							converter: String,
						}),
					},
					pool: {
						min: 2,
						max: 10,
						acquireTimeoutMillis: 10_000,
						idleTimeoutMillis: 30_000,
					},
				},
			},
			KNEX_READ_CONNECTION,
		),
	],
	exports: [KnexModule],
})
export class DbModule {}

import { getEnv } from '@utils/get-env-variable.util';

import { DATABASE_URL } from '@constants/env-variables.constant';

import type { Knex } from 'knex';

const config: Knex.Config = {
	client: 'pg',
	connection: {
		connectionString: getEnv<string>({ key: DATABASE_URL, converter: String }),
	},
	migrations: {
		directory: './src/migrations',
		extension: 'ts',
	},
};

module.exports = config;
